class Solution:
    def resultArray(self, nums):
        import bisect
        # coordinate compress
        sorted_vals = sorted(set(nums))
        rank = {v: i + 1 for i, v in enumerate(sorted_vals)}
        m = len(sorted_vals)

        def make_bit():
            return [0] * (m + 2)

        def update(bit, i):
            while i <= m:
                bit[i] += 1
                i += i & (-i)

        def query(bit, i):
            s = 0
            while i > 0:
                s += bit[i]
                i -= i & (-i)
            return s

        def greater_count(bit, val):
            r = rank[val]
            # count of elements with rank > r = total - prefix(r)
            total = query(bit, m)
            return total - query(bit, r)

        bit1 = make_bit()
        bit2 = make_bit()
        arr1 = [nums[0]]
        arr2 = [nums[1]]
        update(bit1, rank[nums[0]])
        update(bit2, rank[nums[1]])

        for i in range(2, len(nums)):
            v = nums[i]
            g1 = greater_count(bit1, v)
            g2 = greater_count(bit2, v)
            if g1 > g2:
                arr1.append(v)
                update(bit1, rank[v])
            elif g2 > g1:
                arr2.append(v)
                update(bit2, rank[v])
            elif len(arr1) <= len(arr2):
                arr1.append(v)
                update(bit1, rank[v])
            else:
                arr2.append(v)
                update(bit2, rank[v])

        return arr1 + arr2

