var resultArray = function(nums) {
    const sortedVals = [...new Set(nums)].sort((a, b) => a - b);
    const rank = new Map();
    sortedVals.forEach((v, i) => rank.set(v, i + 1));
    const m = sortedVals.length;

    function makeBit() { return new Int32Array(m + 2); }

    function update(bit, i) {
        for (; i <= m; i += i & (-i)) bit[i]++;
    }

    function query(bit, i) {
        let s = 0;
        for (; i > 0; i -= i & (-i)) s += bit[i];
        return s;
    }

    function greaterCount(bit, val) {
        const r = rank.get(val);
        return query(bit, m) - query(bit, r);
    }

    const bit1 = makeBit(), bit2 = makeBit();
    const arr1 = [nums[0]], arr2 = [nums[1]];
    update(bit1, rank.get(nums[0]));
    update(bit2, rank.get(nums[1]));

    for (let i = 2; i < nums.length; i++) {
        const v = nums[i];
        const g1 = greaterCount(bit1, v);
        const g2 = greaterCount(bit2, v);
        if (g1 > g2) {
            arr1.push(v);
            update(bit1, rank.get(v));
        } else if (g2 > g1) {
            arr2.push(v);
            update(bit2, rank.get(v));
        } else if (arr1.length <= arr2.length) {
            arr1.push(v);
            update(bit1, rank.get(v));
        } else {
            arr2.push(v);
            update(bit2, rank.get(v));
        }
    }

    return arr1.concat(arr2);
};
